// TypeScript: Define custom tool
import { Tool } from "@anthropic-ai/agent-sdk";

class DatabaseQueryTool extends Tool {
  name = "database_query";
  description = "Query the database to retrieve customer order history";
  input_schema = {
    type: "object",
    properties: {
      customer_id: { type: "string", description: "Customer ID" }
    },
    required: ["customer_id"]
  };

  async execute(params: { customer_id: string }) {
    // Execute database query
    const result = await db.query(
      "SELECT * FROM orders WHERE customer_id = ?",
      [params.customer_id]
    );
    return result;
  }
}

// TypeScript: Pass tools to Agent
import { Agent } from "@anthropic-ai/agent-sdk";

const agent = new Agent({
  tools: [new DatabaseQueryTool()],
  allowedTools: ["computer", "database_query"]
});

# Python: Handle tool execution
from anthropic import Anthropic

client = Anthropic()

response = client.messages.create(
