import asyncio
from anthropic import AsyncAnthropic

client = AsyncAnthropic()

async def run_agent(prompt):
    # Step 1: Initial message
    response = await client.messages.create(
        model="claude-3-5-sonnet-20241022",
        max_tokens=4096,
        tools=[
            {
                "type": "computer_20241022",
                "name": "computer",
                "display_width_px": 1024,
                "display_height_px": 768
            },
            {
                "type": "function",
                "name": "send_email",
                "description": "Send email via API",
                "input_schema": {
                    "type": "object",
                    "properties": {
                        "to": {"type": "string"},
                        "subject": {"type": "string"},
                        "body": {"type": "string"}
                    },
                    "required": ["to", "subject", "body"]
                }
            }
        ],
        messages=[{"role": "user", "content": prompt}]
    )

    # Step 2: Process tool_use blocks
    for content in response.content:
        if content.type == "tool_use":
            if content.name == "send_email":
                # Execute custom tool
                result = await send_email_api(
                    to=content.input.to,
                    subject=content.input.subject,
                    body=content.input.body
                )

                # Send tool_result back
                response = await client.messages.create(
                    model="claude-3-5-sonnet-20241022",
                    messages=[{
                        "role": "user",
                        "content": [
                            {
                                "type": "tool_result",
                                "tool_use_id": content.id,
                                "content": str(result)
                            }
                        ]
                    }]
                )
            elif content.name == "computer":
                # Execute computer action
                await execute_computer_action(content.input)

                # Take new screenshot
                screenshot = await take_screenshot()

                # Send tool_result with screenshot
                response = await client.messages.create(
                    model="claude-3-5-sonnet-20241022",
                    messages=[{
                        "role": "user",
                        "content": [
                            {
                                "type": "tool_result",
                                "tool_use_id": content.id,
                                "content": [
                                    {
                                        "type": "image",
                                        "source": {
                                            "type": "base64",
                                            "media_type": "image/png",
                                            "data": screenshot
                                        }
                                    }
                                ]
                            }
                        ]
                    }]
                )
